# NOTE: These utilities are intended to be imported by Git hooks via
# `from bertrand_git import ...` (notice no relative paths/leading dot).  The
# `bertrand init` command ensures that this file is copied into the `.git/hooks/`
# directory alongside the hooks themselves, so that the import will always resolve
# properly.  Note that it IS NOT SAFE to import code from third-party libraries or
# across hooks, since the hook names may be rewritten in order to conform to Git's
# expectations.  This is the ONLY file that Bertrand guarantees to be importable from
# downstream hooks.


type GitRefState = Literal["prepared", "committed", "aborted"]


GIT_REF_HEADS_PREFIX = "refs/heads/"
GIT_REF_STATES: frozenset[GitRefState] = frozenset({"prepared", "committed", "aborted"})
GIT_REQUIRE_RELATIVE_PATHS = (
    "git worktree relative path support is required for bare repository mode, but "
    "this git version does not support '--relative-paths' for worktree creation and "
    "move operations.  Please upgrade git to a version that supports this feature "
    "(git 2.52+)."
)


@dataclass(frozen=True)
class GitRefUpdate:
    """A single reference update received from git on stdin."""
    old: str
    new: str
    ref: str

    @property
    def is_head(self) -> bool:
        """
        Returns
        -------
        bool
            True if this update targets `refs/heads/*`.
        """
        return self.ref.startswith(GIT_REF_HEADS_PREFIX)

    @property
    def branch(self) -> str:
        """
        Returns
        -------
        str
            The short branch name for `refs/heads/*` updates.
        """
        return self.ref[len(GIT_REF_HEADS_PREFIX):]

    @property
    def created(self) -> bool:
        """
        Returns
        -------
        bool
            True if this update created a new ref.
        """
        return all(c == "0" for c in self.old) and any(c != "0" for c in self.new)

    @property
    def destroyed(self) -> bool:
        """
        Returns
        -------
        bool
            True if this update deleted an existing ref.
        """
        return any(c != "0" for c in self.old) and all(c == "0" for c in self.new)

    @classmethod
    def parse(cls, stdin: str) -> list[GitRefUpdate]:
        """Parse and validate transaction update lines from stdin.

        Parameters
        ----------
        stdin : str
            The raw stdin input containing reference update lines, typically read from
            the `reference-transaction` hook's standard input stream.

        Returns
        -------
        list[GitRefUpdate]
            A list of parsed reference updates.

        Raises
        ------
        ValueError
            If any line is malformed.
        """
        updates: list[GitRefUpdate] = []
        for index, raw in enumerate(stdin.splitlines(), start=1):
            line = raw.strip()
            if not line:
                continue
            parts = line.split()
            if len(parts) != 3:
                raise ValueError(
                    f"malformed git transaction line {index}: expected "
                    f"'<old> <new> <ref>', got: {raw!r}"
                )
            old, new, ref = (part.strip() for part in parts)
            if not ref:
                raise ValueError(
                    f"malformed git transaction line {index}: ref must not be empty"
                )
            updates.append(cls(old=old, new=new, ref=ref))
        return updates


@dataclass(frozen=True)
class GitRepository:
    """An object-oriented wrapper around a git repository, which simplifies access to
    its branches, worktrees, and other properties.

    Attributes
    ----------
    git_dir : Path, optional
        The path to the repository's .git directory.  If omitted, the repository will
        be by running `git rev-parse --git-common-dir` in the current working
        directory.
    """
    @dataclass(frozen=True)
    class Worktree:
        """A parsed entry from `git worktree list --porcelain`.

        Attributes
        ----------
        path : Path
            The absolute path to the worktree checkout.
        branch : str | None
            The short branch name if this worktree is attached to `refs/heads/*`,
            otherwise None.
        """
        path: Path
        branch: str | None = None

        def __post_init__(self) -> None:
            object.__setattr__(self, "path", self.path.expanduser().resolve())
            if not self.path.exists():
                raise FileNotFoundError(f"worktree path does not exist: {self.path}")
            if not self.path.is_dir():
                raise NotADirectoryError(f"invalid worktree path: {self.path}")

    git_dir: Path

    @property
    def root(self) -> Path:
        """
        Returns
        -------
        Path
            The absolute path to the repository's root directory, which is the parent of
            the .git directory.
        """
        return self.git_dir.parent

    def __post_init__(self) -> None:
        object.__setattr__(self, "git_dir", self.git_dir.expanduser().resolve())

    @classmethod
    async def discover(cls, path: Path | None = None) -> GitRepository | None:
        """Discover the Git repository for the current working directory.

        Parameters
        ----------
        path : Path | None, optional
            An optional path to use as the starting point for discovery.  If None (the
            default), then the current working directory will be used.

        Returns
        -------
        GitRepository | None
            The discovered Git repository, assuming a `path` is inside a Git repository

        Raises
        ------
        CommandError
            If the git command fails, which may indicate that the current directory is
            not within a Git repository.
        """
        result = await run(
            ["git", "rev-parse", "--path-format=absolute", "--git-common-dir"],
            cwd=path,
            check=False,
            capture_output=True
        )
        if result.returncode == 0:
            return cls(git_dir=Path(result.stdout.strip()))
        return None

    @classmethod
    async def resolve(cls, path: Path) -> tuple[GitRepository, Path]:
        """Given a path, resolve an ancestor git repository and compute the
        corresponding worktree path within it.

        Parameters
        ----------
        path : Path
            The input path to resolve a repository and worktree for.  The ancestors
            will be scanned to find the nearest git repository, and the remaining path
            components will be treated as a relative worktree path within the
            repository.  If no repository is found, then the input path will be
            treated as an uninitialized repository, and the worktree will reflect the
            Git installation's default branch (e.g. "master" or "main").  If the
            path leads to a bare repository, then the worktree will resolve to its
            attached HEAD worktree, if it has one.

        Returns
        -------
        tuple[GitRepository, Path]
            A tuple containing the resolved Git repository and the relative worktree
            path within it, accounting for HEAD extensions and nested bare/non-bare
            worktree layouts.  Note that the `GitRepository` may be uninitialized if
            no existing repository was found during resolution.

        Raises
        ------
        OSError
            If the resolved repository is bare and does not support relative paths,
            the resolved worktree is not contained within the repository, or if the
            path leads to a bare repository with a detached HEAD.
        """
        repo = await cls.discover(path)

        # new bare repository
        if repo is None:
            if not await cls.supports_relative_paths():
                raise OSError(GIT_REQUIRE_RELATIVE_PATHS)
            repo = cls(path / ".git")
            return repo, Path(await cls.default_branch())

        # existing bare repository
        if await repo.is_bare():
            if not await cls.supports_relative_paths():
                raise OSError(GIT_REQUIRE_RELATIVE_PATHS)
            worktree = path.relative_to(repo.root)
            if not worktree.parts:  # extend to HEAD worktree
                head = await repo.head_branch()
                if head is None:
                    raise OSError(
                        f"cannot target a bare repository with a detached HEAD: {path}"
                    )
                await repo.sync_worktrees()
                candidate = next(
                    (wt.path for wt in await repo.worktrees() if wt.branch == head),
                    None
                )
                if candidate is None:
                    raise OSError(
                        f"HEAD branch '{head}' is not checked out in any worktree of "
                        f"repository: {path}"
                    )
                if not candidate.is_relative_to(path):
                    raise OSError(
                        f"resolved worktree path '{candidate}' is not contained within "
                        f"repository: {path}"
                    )
                worktree = candidate.relative_to(path)
            elif not any(wt.path == path for wt in await repo.worktrees()):
                raise OSError(
                    f"worktree at {worktree} is not registered as a git worktree of "
                    f"bare repository: {repo.root}"
                )
            return repo, worktree

        # existing non-bare repository
        worktree = path.relative_to(repo.root)
        if worktree.parts and not any(wt.path == path for wt in await repo.worktrees()):
            raise OSError(
                f"nested worktree at {worktree} is not registered as a git worktree "
                f"of non-bare repository: {repo.root}"
            )
        return repo, worktree

    def __bool__(self) -> bool:
        return (
            self.git_dir.exists() and
            self.git_dir.is_dir() and
            subprocess.run(
                ["git", "--git-dir", str(self.git_dir), "rev-parse", "--git-dir"],
                check=False,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
            ).returncode == 0
        )

    async def init(self, *, branch: str | None = None, bare: bool = True) -> None:
        """Initialize a new Git repository at the given path.

        Parameters
        ----------
        branch : str | None, optional
            An optional initial branch name to use for the repository.  If None (the
            default), then the Git installation's default branch will be used (e.g.
            "master" or "main").
        bare : bool, optional
            Whether to create a bare repository (default is True).  If false, then a
            standard repository with a working tree will be created instead.

        Raises
        ------
        CommandError
            If the git command fails.
        """
        self.git_dir.mkdir(parents=True, exist_ok=True)
        cmd = ["git", "init", "--quiet"]
        if branch is not None:
            cmd.extend(["--initial-branch", branch])
        if bare:
            cmd.append("--bare")
        cmd.append(str(self.git_dir))
        await run(cmd)

    async def run(
        self,
        argv: list[str],
        *,
        check: bool = True,
        capture_output: bool | None = False,
        input: str | None = None,
        timeout: float | None = None,
        attempts: int = 1,
        delay: float = 0.1,
        cwd: Path | None = None,
        env: Mapping[str, str] | None = None,
    ) -> CompletedProcess:
        """Run a git command as an asynchronous subprocess wrapper.

        Parameters
        ----------
        argv : list[str]
            The command and its arguments to run, excluding the initial "git".
        check : bool, optional
            Whether to raise a `CommandError` if the command fails (default is True).
            If false, then any errors will be ignored.
        capture_output : bool | None, optional
            If true, then all output will be redirected to the returned
            `CompletedProcess` or `CommandError`, and excluded from the inherited
            stdout/stderr streams.  If false (the default), then the opposite is the
            case, and the returned `CompletedProcess` or `CommandError` will not
            include any captured output.  If None, then output will be "tee'd" to both
            the console and the returned objects simultaneously.  Note that teeing
            output in this way may break TTY behavior for some commands, and is not
            recommended for interactive use.
        input : str | None, optional
            Input to send to the command's stdin (default is None).
        timeout : float | None, optional
            An optional timeout in seconds to wait for the command to complete before
            raising a `TimeoutExpired` exception.  Default is None, which means to wait
            indefinitely.  If zero or negative, a `TimeoutExpired` exception will be
            raised immediately.  Note that this does not reset between `attempts`, so
            the total time spent on retries counts against the timeout.
        attempts : int, optional
            The total number of times to attempt the command.  Defaults to 1, which
            means no retries.  If greater than 1, then any command that exits with a
            nonzero exit code will be re-run after a short delay, up to the specified
            number of times in total.
        delay : float, optional
            The delay in seconds to wait between retries when `attempts` is greater
            than 1.  Default is 0.1 seconds.  Must be non-negative.
        cwd : Path | None, optional
            An optional working directory to run the command in.  If None (the default),
            then the current working directory will be used.
        env : Mapping[str, str] | None, optional
            An optional environment dictionary to use for the command.  If None (the
            default), then the current process's environment will be used.

        Returns
        -------
        CompletedProcess
            The completed process result.

        Raises
        ------
        CommandError
            If the command fails and `check` is True.
        TimeoutExpired
            If the command does not complete within the specified timeout.
        OSError
            If we failed to open the subprocess or its output streams.
        """
        return await run(
            ["git", "--git-dir", str(self.git_dir), *argv],
            check=check,
            capture_output=capture_output,
            input=input,
            timeout=timeout,
            attempts=attempts,
            delay=delay,
            cwd=cwd,
            env=env,
        )

    async def git_path(self, path: Path, *, cwd: Path | None = None) -> Path:
        """Resolve a git-path using `git rev-parse --git-path`.

        Parameters
        ----------
        path : str
            The git-path expression to resolve (e.g. `hooks/pre-commit`).
        cwd : Path | None, optional
            Optional working directory for relative path resolution semantics.

        Returns
        -------
        Path
            The resolved absolute filesystem path.

        Raises
        ------
        ValueError
            If git returned an empty path.
        CommandError
            If the git command fails.
        """
        path_str = path.as_posix()
        result = await self.run(
            ["rev-parse", "--path-format=absolute", "--git-path", path_str],
            capture_output=True,
            cwd=cwd,
        )
        text = result.stdout.strip()
        if not text:
            raise ValueError(f"empty --git-path output for {path_str!r}")
        resolved = Path(text).expanduser()
        if not resolved.is_absolute():
            base = cwd if cwd is not None else self.root
            resolved = (base / resolved).resolve()
        else:
            resolved = resolved.resolve()
        return resolved

    def _parse_bool(self, stdout: str) -> bool:
        value = stdout.strip().lower()
        if value == "true":
            return True
        if value == "false":
            return False
        raise ValueError(f"invalid git boolean output: {stdout!r}")

    @staticmethod
    async def supports_relative_paths() -> bool:
        """
        Returns
        -------
        bool
            True if both `git worktree add` and `git worktree move` support
            `--relative-paths` according to their help output, false otherwise.
        """
        add_help = await run(
            ["git", "worktree", "add", "-h"],
            check=False,
            capture_output=True,
        )
        add_text = f"{add_help.stdout}\n{add_help.stderr}".lower()
        if add_help.returncode != 0 or "--relative-paths" not in add_text:
            return False
        move_help = await run(
            ["git", "worktree", "move", "-h"],
            check=False,
            capture_output=True,
        )
        move_text = f"{move_help.stdout}\n{move_help.stderr}".lower()
        return move_help.returncode == 0 and "--relative-paths" in move_text

    @staticmethod
    async def default_branch() -> str:
        """
        Returns
        -------
        str
            The default branch name configured for this git installation.

        Raises
        ------
        CommandError
            If git commands fail while probing default branch behavior.
        ValueError
            If the default branch could not be determined from git output.
        """
        branch = await run(["git", "var", "GIT_DEFAULT_BRANCH"], capture_output=True)
        result = branch.stdout.strip()
        if not result:
            raise ValueError("default Git branch name could not be determined")
        return result

    async def head_branch(self) -> str | None:
        """
        Returns
        -------
        str | None
            The short branch name of the current HEAD, or None if HEAD is detached.

        Raises
        ------
        CommandError
            If the git command fails with an error.
        ValueError
            If we failed to parse the output or got an empty branch name.
        """
        # attached HEAD: try to read symbolic ref directly
        result = await self.run(
            ["symbolic-ref", "--quiet", "--short", "HEAD"],
            check=False,
            capture_output=True,
        )
        if result.returncode == 0:
            text = result.stdout.strip()
            if not text:
                raise ValueError("empty symbolic-ref output for HEAD")
            return text
        if result.returncode != 1:
            raise CommandError(result.returncode, result.args, result.stdout, result.stderr)

        # detached HEAD: let caller decide what to do
        return None

    async def is_bare(self) -> bool:
        """
        Returns
        -------
        bool
            True if this repository is a bare repository, false otherwise.

        Raises
        ------
        CommandError
            If the git command fails.
        ValueError
            If we failed to parse the output.
        """
        result = await self.run(
            ["rev-parse", "--is-bare-repository"],
            capture_output=True,
        )
        value = result.stdout.strip().lower()
        if value == "true":
            return True
        if value == "false":
            return False
        raise ValueError(f"invalid --is-bare-repository output: {result.stdout!r}")

    async def branches(self) -> frozenset[str]:
        """
        Returns
        -------
        frozenset[str]
            A set of all (short) branch names in the repository.  Note that this only
            includes branches under `refs/heads/`, and not other refs like tags or
            remotes.

        Raises
        ------
        CommandError
            If the git command fails.
        """
        result = await self.run(
            ["for-each-ref", "--format=%(refname:short)", "refs/heads"],
            capture_output=True,
        )
        out = {line.strip() for line in result.stdout.splitlines()}
        out.discard("")  # remove empty lines if any
        return frozenset(out)

    async def worktrees(self) -> tuple[GitRepository.Worktree, ...]:
        """List all local worktrees for the given Git directory.

        Returns
        -------
        tuple[GitRepository.Worktree, ...]
            A tuple of worktree entries.  Includes both attached (with branch) and
            detached (without branch) worktrees, which may be filtered by the caller as
            needed.
        """
        out: list[GitRepository.Worktree] = []
        path: Path | None = None
        branch: str | None = None
        result = await self.run(
            ["worktree", "list", "--porcelain"],
            capture_output=True,
        )
        for raw in result.stdout.splitlines():
            line = raw.strip()
            if not line:
                if path is not None:
                    out.append(self.Worktree(path=path, branch=branch))
                path = None
                branch = None
                continue
            if line.startswith("worktree "):
                path = Path(line[len("worktree "):]).expanduser().resolve()
                continue
            if line.startswith(f"branch {GIT_REF_HEADS_PREFIX}"):
                branch = line[len("branch ") + len(GIT_REF_HEADS_PREFIX):]
        if path is not None:
            out.append(self.Worktree(path=path, branch=branch))
        return tuple(out)

    async def _current_worktree_state(self) -> dict[str, Path]:
        current: dict[str, Path] = {}
        for wt in await self.worktrees():
            if wt.branch is None:
                continue
            existing = current.setdefault(wt.branch, wt.path)
            if existing != wt.path:
                raise FileExistsError(
                    f"multiple worktrees mapped to branch '{wt.branch}': "
                    f"{existing} and {wt.path}"
                )
        return current

    def _intended_worktree_changes(
        self,
        updates: Sequence[GitRefUpdate]
    ) -> tuple[list[str], list[str], list[tuple[str, str]]]:
        # get creation/destruction intent from transaction updates
        _created: dict[str, list[str]] = {}
        _destroyed: dict[str, list[str]] = {}
        created: list[str] = []
        destroyed: list[str] = []
        for update in updates:
            if update.created:
                created.append(update.branch)
                _created.setdefault(update.new, []).append(update.branch)
            elif update.destroyed:
                destroyed.append(update.branch)
                _destroyed.setdefault(update.old, []).append(update.branch)

        # infer rename hints from unambiguous create + destroy pairs on the same object
        renamed: list[tuple[str, str]] = []
        for oid in sorted(set(_created) & set(_destroyed)):
            c = _created[oid]
            d = _destroyed[oid]
            if len(c) == 1 and len(d) == 1:
                old_branch = d[0]
                new_branch = c[0]
                renamed.append((old_branch, new_branch))
                destroyed.remove(old_branch)
                created.remove(new_branch)

        return created, destroyed, renamed

    def _filter_worktree_conflicts(
        self,
        desired: dict[str, Path],
        current: dict[str, Path],
        created: list[str],
    ) -> dict[str, Path]:
        # sort branches by conflict priority, then filter out any whose slash-separated
        # paths would create a nested worktree conflicts
        winners: list[str] = []
        for branch in sorted(desired, key=lambda b: (
            0 if b in current else 1,  # prioritize existing
            0 if b not in created else 1,  # ... then prioritize non-created branches
            b,  # ... then break ties lexically
        )):
            conflict: str | None = None
            for winner in winners:
                if branch == winner:
                    continue
                left_parts = branch.split("/")
                right_parts = winner.split("/")
                min_len = min(len(left_parts), len(right_parts))
                if left_parts[:min_len] == right_parts[:min_len]:
                    conflict = winner
                    break
            if conflict is None:
                winners.append(branch)
                continue
            print(
                f"bertrand: skipping branch '{branch}' due nested path conflict with "
                f"'{conflict}'",
                file=sys.stderr
            )

        return {branch: desired[branch] for branch in winners}

    def _clean_worktree_parents(self, path: Path) -> None:
        # clean up now-empty parent directories up to project root to account for
        # branch names that contain path separators
        cursor = path.parent
        while cursor != self.root:
            try:
                if any(cursor.iterdir()):
                    break
                cursor.rmdir()
            except OSError:
                break
            cursor = cursor.parent

    async def _worktree_belongs_to_repo(self, path: Path, env: dict[str, str]) -> bool:
        result = await run(
            ["git", "-C", str(path), "rev-parse", "--git-common-dir"],
            check=False,
            capture_output=True,
            env=env,
        )
        if result.returncode != 0:
            return False
        owner = Path(result.stdout.strip()).expanduser()
        if not owner.is_absolute():
            owner = path / owner
        return self.git_dir == owner.expanduser().resolve()

    async def _strip_env(self, env: dict[str, str] | None = None) -> dict[str, str]:
        """Remove repo-local git environment variables from the given environment mapping.

        Parameters
        ----------
        env : dict[str, str] | None, optional
            The environment mapping to strip git variables from.  If None, the current
            process environment will be used.  Defaults to None.

        Returns
        -------
        dict[str, str]
            The filtered environment variables with repo-local keys removed.
        """
        env = dict(os.environ if env is None else env)
        local = await self.run(
            ["rev-parse", "--local-env-vars"],
            check=False,
            capture_output=True,
            env=env
        )
        if local.returncode == 0:
            keys = [key.strip() for key in local.stdout.splitlines() if key.strip()]
        else:
            keys = ["GIT_DIR", "GIT_WORK_TREE", "GIT_COMMON_DIR"]  # best-effort fallback
        for key in keys:
            env.pop(key, None)
        return env

    async def create_worktree(
        self,
        branch: str,
        *,
        target: Path | None = None,
        create_branch: bool = True,
        quiet: bool = False,
    ) -> None:
        """Create a new worktree for the given branch at the specified target path.

        Parameters
        ----------
        branch : str
            The short branch name to create a worktree for.
        target : Path | None, optional
            The target path to create the worktree at.  Must not already exist.
        create_branch : bool, optional
            If True (the default), then the branch will be created if it does not
            already exist.  If False, then the branch must already exist in the
            repository.
        quiet : bool, optional
            If True, then suppress any non-error output from the git command.  Default
            is False.

        Raises
        ------
        FileExistsError
            If the target path already exists.
        CommandError
            If the git command fails.
        """
        if target is None:
            target = self.root / branch
        if target.exists():
            raise FileExistsError("path already exists")
        target.parent.mkdir(parents=True, exist_ok=True)
        cmd = ["worktree", "add", "--relative-paths"]
        if create_branch:
            if branch not in await self.branches():
                cmd.extend(["-b", branch, str(target)])
            else:
                cmd.extend([str(target), branch])
        else:
            cmd.extend([str(target), branch])
        await self.run(cmd, capture_output=quiet)

    async def move_worktree(
        self,
        branch: str,
        *,
        source: Path | None = None,
        target: Path | None = None,
    ) -> None:
        """Move the worktree for the given branch from the source path to the target
        path.

        Parameters
        ----------
        branch : str
            The short branch name to move the worktree for.
        source : Path | None, optional
            The current path of the worktree to move.  If None, the path will be derived
            from the current worktree state for the given branch.  Defaults to None.
        target : Path | None, optional
            The destination path for the worktree.  If None, the worktree will be moved
            to its default location based on the branch name, if it is not already
            there.  Defaults to None.

        Raises
        ------
        FileNotFoundError
            If the source path does not exist or could not be derived from the current
            worktree state.
        NotADirectoryError
            If the source path or target path exists but is not a directory.
        FileExistsError
            If the target path already exists, and is not the same as the source path.
        """
        if source is None:
            for wt in await self.worktrees():
                if wt.branch == branch:
                    source = wt.path
                    break
            if source is None:
                raise FileNotFoundError(f"no worktree found for branch '{branch}'")
        if not source.exists():
            raise FileNotFoundError(f"worktree path does not exist: {source}")
        if not source.is_dir():
            raise NotADirectoryError(f"worktree is not a directory: {source}")

        if target is None:
            target = self.root / branch
        if target == source:
            return
        if target.exists():
            raise FileExistsError(f"target path already exists: {target}")

        target.parent.mkdir(parents=True, exist_ok=True)
        await self.run(
            ["worktree", "move", "--relative-paths", str(source), str(target)],
            capture_output=True
        )
        self._clean_worktree_parents(source)

    async def destroy_worktree(
        self,
        branch: str,
        *,
        target: Path | None = None,
    ) -> bool:
        """Destroy the worktree for the given branch, if it exists and is clean.

        Parameters
        ----------
        branch : str
            The short branch name to destroy the worktree for.
        target : Path | None, optional
            An optional path to the worktree to destroy.  If None (the default), then
            the path will be derived from the current worktree state for the given
            branch.

        Returns
        -------
        bool
            True if the worktree was successfully destroyed or did not exist, false if
            the worktree exists but could not be destroyed due to dirty state.

        Raises
        ------
        FileNotFoundError
            If the target path does not exist or could not be derived from the current
            worktree state.
        NotADirectoryError
            If the target path exists but is not a directory.
        RuntimeError
            If the target path does not belong to this repository.
        """
        if target is None:
            for wt in await self.worktrees():
                if wt.branch == branch:
                    target = wt.path
                    break
            if target is None:
                raise FileNotFoundError(f"no worktree found for branch '{branch}'")
        if not target.exists():
            raise FileNotFoundError(f"worktree path does not exist: {target}")
        if not target.is_dir():
            raise NotADirectoryError(f"worktree is not a directory: {target}")

        # verify that the worktree is clean and objectively belongs to this repository
        # before attempting deletion
        env = await self._strip_env()
        if not await self._worktree_belongs_to_repo(target, env):
            raise RuntimeError(
                f"worktree path does not belong to this repository: {target}"
            )
        clean = await run(
            ["git", "-C", str(target), "status", "--porcelain"],
            capture_output=True,
            env=env,
        )
        if clean.stdout.strip():
            return False

        # remove the worktree using git, which will also properly clean up the
        # associated gitdir and any linked metadata
        await self.run(["worktree", "remove", str(target)], capture_output=True)
        self._clean_worktree_parents(target)
        return True

    async def sync_worktrees(self, updates: Sequence[GitRefUpdate] = ()) -> None:
        """Converge worktrees to the authoritative branch set using a hybrid
        intent-first delta pass.

        Parameters
        ----------
        updates : Sequence[GitRefUpdate], optional
            The parsed reference updates received from git on stdin, which will be used
            to derive explicit intent for branch creations and destructions, as well as
            implicit hints for branch renames where creation and destruction are paired
            on the same object.  If omitted, then convergence will transform directly
            from the current state to the desired state without any intent-based
            guidance.
        """
        # non-bare repositories are treated as single-worktree mode
        if not await self.is_bare():
            return

        # derive current and desired branch-to-path mappings
        current = await self._current_worktree_state()
        desired = {branch: (self.root / branch) for branch in await self.branches()}

        # derive explicit intent from transaction updates, preserving order
        created, destroyed, renamed = self._intended_worktree_changes(updates)
        desired = self._filter_worktree_conflicts(desired, current, created)

        # apply rename hints first (when they map cleanly to current state)
        for old_branch, new_branch in renamed:
            source = current.get(old_branch)
            if source is None:
                continue
            target = desired.get(new_branch)
            if target is None or new_branch in current:
                continue
            try:
                await self.move_worktree(new_branch, source=source, target=target)
                current.pop(old_branch, None)
                current[new_branch] = target
            except Exception as err:
                print(
                    f"bertrand: failed to move worktree for branch '{new_branch}' from "
                    f"{source} to {target}:\n{err}"
                )

        # apply explicit destroys for branches still present in current state
        for branch in destroyed:
            path = current.get(branch)
            if path is None or branch in desired:
                continue
            try:
                if await self.destroy_worktree(branch, target=path):
                    current.pop(branch, None)
            except Exception as err:
                print(
                    f"bertrand: failed to destroy worktree for branch '{branch}' at "
                    f"{path}:\n{err}"
                )

        # apply explicit creates for branches that are still missing
        for branch in created:
            if branch in current or branch not in desired:
                continue
            target = desired[branch]
            try:
                await self.create_worktree(branch, target=target, create_branch=True)
                current[branch] = target
            except Exception as err:
                print(
                    f"bertrand: failed to create worktree for branch '{branch}' at "
                    f"{target}:\n{err}"
                )

        # remove branches no longer present in the repository
        stale = set(current) - set(desired)
        for branch in sorted(stale):
            path = current[branch]
            try:
                if await self.destroy_worktree(branch, target=path):
                    current.pop(branch, None)
            except Exception as err:
                print(
                    f"bertrand: failed to destroy worktree for branch '{branch}' at "
                    f"{path}:\n{err}"
                )

        # move branches that are present but located at non-canonical paths
        shared = set(current) & set(desired)
        for branch in sorted(shared):
            source = current[branch]
            target = desired[branch]
            if source == target:
                continue
            try:
                await self.move_worktree(branch, source=source, target=target)
                current[branch] = target
            except Exception as err:
                print(
                    f"bertrand: failed to move worktree for branch '{branch}' from "
                    f"{source} to {target}:\n{err}"
                )

        # create worktrees for branches that don't yet have one
        missing = set(desired) - set(current)
        for branch in sorted(missing):
            target = desired[branch]
            try:
                await self.create_worktree(branch, target=target, create_branch=False)
                current[branch] = target
            except Exception as err:
                print(
                    f"bertrand: failed to create worktree for branch '{branch}' at "
                    f"{target}:\n{err}"
                )
